def nextPermutation(arr: Array[Int]): Boolean = {
    var i = arr.length - 2
    while (i >= 0 && arr(i) >= arr(i + 1)) {
        i -= 1
    }
    if (i < 0) {
        return false
    }
    var j = arr.length - 1
    while (arr(j) <= arr(i)) {
        j -= 1
    }
    val temp = arr(i)
    arr(i) = arr(j)
    arr(j) = temp
    var left = i + 1
    var right = arr.length - 1
    while (left < right) {
        val tmp = arr(left)
        arr(left) = arr(right)
        arr(right) = tmp
        left += 1
        right -= 1
    }
    true
}

def solve(n: Long): Long = {
    val n_big = if (n == 0) BigInt(0) else BigInt(n)
    val nStr = n_big.toString
    val len_n = nStr.length

    var best: Option[BigInt] = None

    for (bitmap <- 1 until 512) {
        val set = (1 to 9).filter(d => (bitmap & (1 << (d - 1))) != 0).toList
        val L = set.sum
        if (L >= len_n) {
            val oddCount = set.count(_ % 2 == 1)
            if (oddCount <= 1) {
                val center = if (oddCount == 1) {
                    Some(set.filter(_ % 2 == 1).head)
                } else {
                    None
                }

                var T_list = List[Int]()
                for (d <- set) {
                    val num = if (d % 2 == 0) d / 2 else (d - 1) / 2
                    T_list = T_list ::: List.fill(num)(d)
                }
                val M = T_list.size

                def toCandidateString(leftHalf: Array[Int]): String = {
                    val leftStr = leftHalf.mkString
                    val rightStr = leftStr.reverse
                    center match {
                        case None => leftStr + rightStr
                        case Some(mid) => leftStr + mid.toString + rightStr
                    }
                }

                val arr = T_list.sorted.toArray
                var candidate = BigInt(toCandidateString(arr))

                if (L > len_n) {
                    if (best.isEmpty || candidate < best.get) {
                        best = Some(candidate)
                    }
                } else {
                    if (candidate > n_big) {
                        if (best.isEmpty || candidate < best.get) {
                            best = Some(candidate)
